mapper.select:
SELECT COUNT(1)
FROM course_schedule cs
JOIN sys_section_time ss ON cs.start_section_id = ss.id
JOIN sys_section_time se ON cs.end_section_id = se.id
WHERE cs.teacher_id = #{teacherId}
  AND cs.academic_year = #{academicYear}
  AND cs.semester = #{semester}
  AND cs.weekday = #{weekday}
  /* 节次范围重叠: MAX(startNo1, startNo2) <= MIN(endNo1, endNo2) */
  AND GREATEST(ss.section_no, #{startSectionNo}) <= LEAST(se.section_no, #{endSectionNo})
  /* 周次范围重叠: MAX(startWeek1, startWeek2) <= MIN(endWeek1, endWeek2) */
  AND GREATEST(cs.start_week, #{startWeek}) <= LEAST(cs.end_week, #{endWeek})
  /* 周次类型可重叠: 非(一方单周+另一方双周) */
  AND NOT (cs.week_type = 1 AND #{weekType} = 2)
  AND NOT (cs.week_type = 2 AND #{weekType} = 1)

  AND cs.id != #{excludeId}

SELECT COUNT(1)
FROM course_schedule cs
JOIN sys_section_time ss ON cs.start_section_id = ss.id
JOIN sys_section_time se ON cs.end_section_id = se.id
WHERE cs.classroom_id = #{classroomId}
  AND cs.academic_year = #{academicYear}
  AND cs.semester = #{semester}
  AND cs.weekday = #{weekday}
  AND GREATEST(ss.section_no, #{startSectionNo}) <= LEAST(se.section_no, #{endSectionNo})
  AND GREATEST(cs.start_week, #{startWeek}) <= LEAST(cs.end_week, #{endWeek})
  AND NOT (cs.week_type = 1 AND #{weekType} = 2)
  AND NOT (cs.week_type = 2 AND #{weekType} = 1)

  AND cs.id != #{excludeId}

SELECT cs.id, c.name AS courseName, t.name AS teacherName, cr.name AS classroomName, cs.academic_year AS academicYear, cs.semester, cs.weekday, ss.section_no AS startSectionNo, se.section_no AS endSectionNo, ss.start_time AS startSectionTime, se.end_time AS endSectionTime, cs.start_week AS startWeek, cs.end_week AS endWeek, cs.week_type AS weekType, cs.student_count AS studentCount FROM course_schedule cs LEFT JOIN course c ON cs.course_id = c.id LEFT JOIN teacher t ON cs.teacher_id = t.id LEFT JOIN classroom cr ON cs.classroom_id = cr.id LEFT JOIN sys_section_time ss ON cs.start_section_id = ss.id LEFT JOIN sys_section_time se ON cs.end_section_id = se.id WHERE cs.status IN (0, 1, 2)
AND cs.teacher_id = #{teacherId}
ORDER BY cs.academic_year DESC, cs.semester DESC, cs.weekday ASC, ss.section_no ASC

SELECT cs.id, c.name AS courseName, t.name AS teacherName, cr.name AS classroomName, cs.academic_year AS academicYear, cs.semester, cs.weekday, ss.section_no AS startSectionNo, se.section_no AS endSectionNo, ss.start_time AS startSectionTime, se.end_time AS endSectionTime, cs.start_week AS startWeek, cs.end_week AS endWeek, cs.week_type AS weekType, cs.student_count AS studentCount FROM course_schedule cs LEFT JOIN course c ON cs.course_id = c.id LEFT JOIN teacher t ON cs.teacher_id = t.id LEFT JOIN classroom cr ON cs.classroom_id = cr.id LEFT JOIN sys_section_time ss ON cs.start_section_id = ss.id LEFT JOIN sys_section_time se ON cs.end_section_id = se.id WHERE cs.academic_year = #{academicYear} AND cs.semester = #{semester} AND cs.weekday = #{currentWeekday} AND #{currentWeek} BETWEEN cs.start_week AND cs.end_week /* weekType 匹配 */ AND (cs.week_type = 0 OR (cs.week_type = 1 AND #{currentWeek} % 2 = 1) OR (cs.week_type = 2 AND #{currentWeek} % 2 = 0)) /* 节次匹配：当前节次落在排课的节次范围内（如果当前节次可确定） */
AND ss.section_no <= #{currentSectionNo} AND se.section_no >= #{currentSectionNo}
AND cs.teacher_id = #{teacherId}
ORDER BY ss.section_no ASC

SELECT cs.id, cs.weekday,
cs.start_section_id AS startSectionId, ss.section_no AS startSectionNo, ss.section_name AS startSectionName, ss.start_time AS startSectionTime,
cs.end_section_id AS endSectionId, se.section_no AS endSectionNo, se.section_name AS endSectionName, se.end_time AS endSectionTime,
c.name AS courseName, t.name AS teacherName, cr.name AS classroomName,
cs.start_week AS startWeek, cs.end_week AS endWeek, cs.week_type AS weekType, cs.student_count AS studentCount, cs.remark FROM course_schedule cs LEFT JOIN course c ON cs.course_id = c.id LEFT JOIN teacher t ON cs.teacher_id = t.id LEFT JOIN classroom cr ON cs.classroom_id = cr.id LEFT JOIN sys_section_time ss ON cs.start_section_id = ss.id LEFT JOIN sys_section_time se ON cs.end_section_id = se.id WHERE cs.academic_year = #{academicYear} AND cs.semester = #{semester}
AND cs.teacher_id = #{teacherId}
AND cs.classroom_id = #{classroomId}
ORDER BY cs.weekday ASC, ss.section_no ASC
